import { AgentExecutor } from 'langchain/agents';
import { ConversationBufferMemory } from 'langchain/memory';

function detectTokenOverflow(executor: AgentExecutor, maxTokens: number = 12000): boolean {
  const memory = executor.memory as ConversationBufferMemory;
  const messages = memory.chatMemory.messages;

  // Simple token estimation: 4 chars per token
  const tokenEstimate = messages.reduce((sum, msg) => {
    return sum + Math.ceil(msg.content.length / 4);
  }, 0);

  return tokenEstimate > maxTokens;
}

// Usage
const hasOverflow = detectTokenOverflow(agentExecutor);

