import { ConversationBufferMemory } from 'langchain/memory';

function pruneContext(memory: ConversationBufferMemory, maxTokens: number = 8000): void {
  const messages = memory.chatMemory.messages;
  let currentTokens = 0;

  // Prune from oldest until under limit
  while (messages.length > 0 && currentTokens < maxTokens) {
    const oldest = messages.shift()!;
    currentTokens += Math.ceil(oldest.content.length / 4);
  }
}

// Before agent.invoke()
pruneContext(agentExecutor.memory as ConversationBufferMemory);
const result = await agentExecutor.invoke({ input: userInput });

